import numpy as np

def relu(x: np.ndarray) -> np.ndarray:
    return np.maximum(0, x)

def batch_norm(x: np.ndarray, gamma: np.ndarray, beta: np.ndarray,
               eps: float = 1e-5) -> np.ndarray:
    # x: (N, C, H, W), normalize over N, H, W per channel
    mean = x.mean(axis=(0, 2, 3), keepdims=True)
    var = x.var(axis=(0, 2, 3), keepdims=True)
    x_norm = (x - mean) / np.sqrt(var + eps)
    return gamma.reshape(1, -1, 1, 1) * x_norm + beta.reshape(1, -1, 1, 1)

def conv3x3(x: np.ndarray, W: np.ndarray, b: np.ndarray,
            stride: int = 1, padding: int = 1) -> np.ndarray:
    N, C_in, H, W_in = x.shape
    C_out, _, kH, kW = W.shape
    if padding > 0:
        x = np.pad(x, ((0,0),(0,0),(padding,padding),(padding,padding)))
    H_out = (x.shape[2] - kH) // stride + 1
    W_out = (x.shape[3] - kW) // stride + 1
    out = np.zeros((N, C_out, H_out, W_out), dtype=x.dtype)
    for n in range(N):
        for co in range(C_out):
            for i in range(H_out):
                for j in range(W_out):
                    patch = x[n, :, i*stride:i*stride+kH, j*stride:j*stride+kW]
                    out[n, co, i, j] = float(np.sum(patch * W[co])) + b[co]
    return out

def residual_block(x, W1, b1, gamma1, beta1, W2, b2, gamma2, beta2,
                   W_proj=None, b_proj=None, stride=1):
    shortcut = x
    # First conv -> BN -> ReLU
    out = conv3x3(x, W1, b1, stride=stride, padding=1)
    out = batch_norm(out, gamma1, beta1)
    out = relu(out)
    # Second conv -> BN
    out = conv3x3(out, W2, b2, stride=1, padding=1)
    out = batch_norm(out, gamma2, beta2)
    # Projection shortcut
    if W_proj is not None:
        # 1x1 conv shortcut
        N, C_in, H, W_in = shortcut.shape
        C_out = W_proj.shape[0]
        if stride > 1 or C_in != C_out:
            padded = shortcut
            H_out = (H - 1) // stride + 1
            W_out = (W_in - 1) // stride + 1
            proj = np.zeros((N, C_out, H_out, W_out), dtype=shortcut.dtype)
            for n in range(N):
                for co in range(C_out):
                    for i in range(H_out):
                        for j in range(W_out):
                            proj[n, co, i, j] = float(np.sum(padded[n, :, i*stride, j*stride] * W_proj[co, :, 0, 0])) + b_proj[co]
            shortcut = proj
    return relu(out + shortcut)
